        require(!_initialized || _initializing, "ALREADY_INITIALIZED");
        bool isTopLevel = !_initializing;

        if (isTopLevel) { _initializing = true; _initialized = true; }

        _;

        if (isTopLevel) _initializing = false;
    }
}

